CompletableFuture<String> clientPause(long timeoutMillis, Route route);
CompletableFuture<String> clientPause(long timeoutMillis, ClientPauseMode mode, Route route);
CompletableFuture<String> clientUnpause(Route route);

// Enum in glide.api.models.commands
public enum ClientPauseMode { ALL, WRITE }
```

